function Avatar({ size = 48, border = false }) {
  return (
    <img
      style={{
        width: size,
        height: size,
        border: border ? '2px solid blue' : 'none',
      }}
      src="/avatar.png"
      alt="avatar"
    />
  );
}

// size = 48  (omitted → undefined → default applies)
<Avatar />

// size = 64  (passed → 64 is used)
<Avatar size={64} />

// size = 48  (explicit undefined → default applies)
<Avatar size={undefined} />

// size = null  (null is NOT undefined → default does NOT apply; component receives null)
<Avatar size={null} />

function Button({
  label,                    // required — no default
  variant    = 'primary',   // string default
  size       = 'md',        // string default
  disabled   = false,       // boolean default
  fullWidth  = false,       // boolean default
  onClick    = null,        // function default (null means "no handler")
  icon       = null,        // element default
  className  = '',          // empty string default
}) {
  return (
    <button
      className={`btn btn-${variant} btn-${size}${fullWidth ? ' w-full' : ''} ${className}`.trim()}
      disabled={disabled}
      onClick={onClick ?? undefined}
    >
      {icon && <span className="icon">{icon}</span>}
      {label}
    </button>
  );
}

function Button({ label, variant, size, disabled }) {
  return (
    <button className={`btn btn-${variant} btn-${size}`} disabled={disabled}>
      {label}
    </button>
  );
}

Button.defaultProps = {
  variant:  'primary',
  size:     'md',
  disabled: false,
};

// Fine for simple display components
function TagList({ tags = [] }) {
  return <ul>{tags.map(t => <li key={t}>{t}</li>)}</ul>;
}

// Problem when used in deps:
const EMPTY = [];   // stable reference — defined outside the component

function TagList({ tags = EMPTY }) {
  useEffect(() => {
    console.log('tags changed', tags);
  }, [tags]);        // no spurious re-runs when tags is omitted

  return <ul>{tags.map(t => <li key={t}>{t}</li>)}</ul>;
}

interface AvatarProps {
  name:      string;
  size?:     number;   // optional; caller may omit it
  isOnline?: boolean;
  className?: string;
}

function Avatar({
  name,
  size      = 48,
  isOnline  = false,
  className = '',
}: AvatarProps) {
  // Inside here: size is 'number' (not 'number | undefined')
  // TypeScript knows the default filled in undefined
  return (
    <div className={`avatar ${className}`} style={{ width: size, height: size }}>
      <img src={`/avatars/${name}.jpg`} alt={name} />
      {isOnline && <span className="dot" />}
    </div>
  );
}

// Default variant is 'primary'; override to 'danger'
<Button label="Delete" variant="danger" />

// Default size is 'md'; override to 'lg'
<Button label="Submit" size="lg" />

// Override multiple defaults at once
<Button label="Confirm" variant="success" size="sm" fullWidth />

// Uncontrolled — React sets the initial DOM value but doesn't manage updates
<input type="text" defaultValue="Alice" />

// Controlled — React owns the value at all times
<input type="text" value={name} onChange={e => setName(e.target.value)} />

const AccordionContext = React.createContext({
  openId:    null,
  onToggle:  () => {},
});

function Accordion({ children, defaultOpenId = null }) {
  const [openId, setOpenId] = React.useState(defaultOpenId);

  return (
    <AccordionContext.Provider value={{ openId, onToggle: setOpenId }}>
      <div className="accordion">{children}</div>
    </AccordionContext.Provider>
  );
}

// defaultOpenId defaults to null (all panels closed)
<Accordion>
  <Panel id="a" title="Section A">Content A</Panel>
  <Panel id="b" title="Section B">Content B</Panel>
</Accordion>

// Open panel 'a' on first render
<Accordion defaultOpenId="a">
  <Panel id="a" title="Section A">Content A</Panel>
</Accordion>

function Button({ variant = 'secondary', ...rest }) {
  return <button className={`btn btn-${variant}`} {...rest} />;
}

// Caller doesn't pass variant → default 'secondary' applies
<Button onClick={handleSave}>Save</Button>

// Caller overrides the default
<Button variant="primary" onClick={handleSubmit}>Submit</Button>

// ❌ Wrong order — caller can unintentionally pass variant and win
function Button(props) {
  return <button {...props} className={`btn btn-${props.variant ?? 'secondary'}`} />;
}

// ✓ Explicit destructuring prevents this ambiguity entirely
function Button({ variant = 'secondary', className = '', ...rest }) {
  return <button {...rest} className={`btn btn-${variant} ${className}`.trim()} />;
}

import { render, screen } from '@testing-library/react';
import Avatar from './Avatar';

// Component: function Avatar({ size = 48, src, alt = 'avatar' }) { ... }

test('renders with defaults when no props given', () => {
  const { container } = render(<Avatar src="/img.png" />);
  const img = container.querySelector('img');
  expect(img).toHaveAttribute('alt', 'avatar');  // default applied
  expect(img).toHaveStyle({ width: '48px' });      // size default
});

test('override wins over default', () => {
  const { container } = render(<Avatar src="/img.png" size={96} alt="User photo" />);
  const img = container.querySelector('img');
  expect(img).toHaveAttribute('alt', 'User photo');
  expect(img).toHaveStyle({ width: '96px' });
});

test('null bypasses the default', () => {
  // Passing null explicitly means: "I want no alt", NOT "use the default"
  const { container } = render(<Avatar src="/img.png" alt={null} />);
  const img = container.querySelector('img');
  expect(img).toHaveAttribute('alt', '');  // null rendered as empty string in JSX
});

// Card.jsx — compound component with sensible sub-component defaults
function Card({ children, elevation = 1, radius = 'md' }) {
  return (
    <div className={`card shadow-${elevation} rounded-${radius}`}>
      {children}
    </div>
  );
}

Card.Header = function Header({ children, divider = true }) {
  return (
    <>
      <header className="card-header">{children}</header>
      {divider && <hr />}
    </>
  );
};

Card.Body = function Body({ children, padding = 'md' }) {
  return <div className={`card-body p-${padding}`}>{children}</div>;
};

Card.Footer = function Footer({ children, align = 'right' }) {
  return <footer className={`card-footer text-${align}`}>{children}</footer>;
};

// Usage — only override what you need:
<Card elevation={2}>
  <Card.Header>Title</Card.Header>
  <Card.Body>Content</Card.Body>
  <Card.Footer align="left">Actions</Card.Footer>
</Card>

// Controlled input — `value` must never be undefined (turns controlled→uncontrolled)
function SearchBox({ value, onChange, placeholder = 'Search…' }) {
  // `value` has no default intentionally — the caller MUST provide it
  return (
    <input
      type="search"
      value={value}        // no default: if caller omits this, React warns
      onChange={onChange}
      placeholder={placeholder}
    />
  );
}

// Uncontrolled input — safe to provide `defaultValue` from a prop default
function SearchBox({ defaultQuery = '', placeholder = 'Search…', onSearch }) {
  const ref = useRef(null);
  return (
    <input
      type="search"
      defaultValue={defaultQuery}   // prop default sets the initial DOM value
      placeholder={placeholder}
      onKeyDown={e => e.key === 'Enter' && onSearch(ref.current.value)}
      ref={ref}
    />
  );
}

// ❌ New array on every render — breaks memo and effects
function TagList({ tags = [] }) {
  useEffect(() => {
    console.log('tags changed', tags);
  }, [tags]); // fires on every render even when caller passes nothing!
  return <ul>{tags.map(t => <li key={t}>{t}</li>)}</ul>;
}

// ✓ Move the constant outside the component (module scope, created once)
const EMPTY_TAGS = [];

function TagList({ tags = EMPTY_TAGS }) {
  useEffect(() => {
    console.log('tags changed', tags);
  }, [tags]); // stable reference: fires only when the caller's array changes
  return <ul>{tags.map(t => <li key={t}>{t}</li>)}</ul>;
}

// toast/Toast.jsx
const NOOP = () => {};
const DEFAULT_ACTIONS = [];

function Toast({
  // Strings — simple inline defaults
  message,                        // required: no default
  title = null,                   // null = "don't render a title heading"
  variant = 'info',               // 'info' | 'success' | 'warning' | 'error'

  // Numbers
  duration = 4000,                // ms before auto-dismiss; 0 = never

  // Booleans
  dismissible = true,
  showIcon   = true,

  // Stable references (module-level constants)
  actions = DEFAULT_ACTIONS,      // [{ label, onClick }]

  // Optional callbacks
  onDismiss = NOOP,
}) {
  const [visible, setVisible] = React.useState(true);

  React.useEffect(() => {
    if (duration === 0) return;
    const id = setTimeout(() => { setVisible(false); onDismiss(); }, duration);
    return () => clearTimeout(id);
  }, [duration, onDismiss]);

  if (!visible) return null;

  return (
    <div role="alert" className={`toast toast--${variant}`}>
      {showIcon && <span className="toast__icon" aria-hidden />}
      <div className="toast__body">
        {/* null title: heading simply not rendered */}
        {title !== null && <strong className="toast__title">{title}</strong>}
        <p>{message}</p>
      </div>
      {actions.map(({ label, onClick }) => (
        <button key={label} onClick={onClick} className="toast__action">
          {label}
        </button>
      ))}
      {dismissible && (
        <button
          onClick={() => { setVisible(false); onDismiss(); }}
          aria-label="Dismiss"
          className="toast__close"
        />
      )}
    </div>
  );
}

export default Toast;
